const incoming = $input.first().json;
const payload = incoming.body ?? incoming;
const normalizeResolution = (candidate) => {
  const resolution = candidate?.resolution && typeof candidate.resolution === 'object' ? candidate.resolution : {};
  return {
    declaredSpec: String(resolution.declaredSpec ?? candidate.currentVersion ?? ''),
    specKind: String(resolution.specKind ?? 'unknown'),
    registryPackageName: resolution.registryPackageName ? String(resolution.registryPackageName) : undefined,
    wantedVersion: resolution.wantedVersion ? String(resolution.wantedVersion) : undefined,
    latestVersion: resolution.latestVersion ? String(resolution.latestVersion) : undefined,
    comparisonStatus: String(resolution.comparisonStatus ?? 'unresolved'),
    requiresManualReview: Boolean(resolution.requiresManualReview ?? false),
    deprecationStatus: String(resolution.deprecationStatus ?? (candidate.deprecated ? 'wanted_deprecated' : 'none')),
    deprecationMessage: resolution.deprecationMessage ? String(resolution.deprecationMessage) : undefined,
    deprecationSourceVersion: resolution.deprecationSourceVersion ? String(resolution.deprecationSourceVersion) : undefined,
    peerOptional: Boolean(resolution.peerOptional ?? false)
  };
};
for (const key of ['analysisId', 'projectName', 'dependencyStats', 'candidates']) {
  if (payload[key] === undefined || payload[key] === null) {
    throw new Error(`Missing field: ${key}`);
  }
}
if (!Array.isArray(payload.candidates)) {
  throw new Error('candidates must be an array');
}
return [{ json: { analysisId: String(payload.analysisId), projectName: String(payload.projectName), dependencyStats: { total: Number(payload.dependencyStats.total ?? 0), outdated: Number(payload.dependencyStats.outdated ?? 0), majors: Number(payload.dependencyStats.majors ?? 0), deprecated: Number(payload.dependencyStats.deprecated ?? 0) }, candidates: payload.candidates.map((candidate) => ({ name: String(candidate.name ?? ''), currentVersion: String(candidate.currentVersion ?? ''), latestVersion: String(candidate.latestVersion ?? ''), group: String(candidate.group ?? 'dependencies'), diffType: String(candidate.diffType ?? 'unknown'), deprecated: Boolean(candidate.deprecated ?? false), publishedAt: candidate.publishedAt ?? null, repositoryUrl: candidate.repositoryUrl ?? null, riskScore: Number(candidate.riskScore ?? 0), sourceUrls: Array.isArray(candidate.sourceUrls) ? candidate.sourceUrls.map((entry) => String(entry)) : [], resolution: normalizeResolution(candidate) })).filter((candidate) => candidate.name.length > 0) } }];

const input = $input.first().json;
const normalizeUrl = (value) => {
  if (!value || typeof value !== 'string') return null;
  return value.replace(/^git\+/, '').replace(/\.git$/i, '').replace(/^ssh:\/\/git@github.com\//, 'https://github.com/').replace(/^git@github.com:/, 'https://github.com/').replace(/^git:\/\//, 'https://');
};
const candidates = input.candidates.map((candidate) => {
  const repositoryUrl = normalizeUrl(candidate.repositoryUrl);
  const sourceUrls = Array.isArray(candidate.sourceUrls) ? candidate.sourceUrls.map((url) => normalizeUrl(url)).filter(Boolean) : [];
  if (repositoryUrl && !sourceUrls.includes(repositoryUrl)) {
    sourceUrls.push(repositoryUrl);
  }
  if (!sourceUrls.some((url) => url.includes('npmjs.com/package'))) {
    sourceUrls.unshift(`https://www.npmjs.com/package/${candidate.name}`);
  }
  return { ...candidate, repositoryUrl, sourceUrls, publishedAt: candidate.publishedAt || null, riskScore: Math.max(0, Math.min(100, Number(candidate.riskScore ?? 0))) };
}).sort((left, right) => right.riskScore - left.riskScore || left.name.localeCompare(right.name));
return [{ json: { ...input, candidates } }];

const data = $input.first().json;
const ranked = [...data.candidates];
const needsManualReview = (candidate) => Boolean(candidate?.resolution?.requiresManualReview);
const deepNames = new Set();
for (const candidate of ranked) {
  if (candidate.diffType === 'major' || candidate.deprecated || needsManualReview(candidate)) {
    deepNames.add(candidate.name);
  }
}
for (const candidate of ranked) {
  if (deepNames.size >= 8) break;
  deepNames.add(candidate.name);
}
const deepCandidates = ranked.filter((candidate) => deepNames.has(candidate.name)).slice(0, 8);
const shallowCandidates = ranked.filter((candidate) => !deepNames.has(candidate.name));
const quickWins = ranked.filter((candidate) => ['patch', 'minor'].includes(candidate.diffType) && !candidate.deprecated && !needsManualReview(candidate)).slice(0, 8);
const highRisk = ranked.filter((candidate) => candidate.diffType === 'major' || candidate.deprecated || candidate.riskScore >= 70 || needsManualReview(candidate)).slice(0, 8);
return [{ json: { analysisId: data.analysisId, projectName: data.projectName, dependencyStats: data.dependencyStats, allCandidates: ranked, deepCandidates, shallowCandidates, quickWins, highRisk, totalDeepCandidates: deepCandidates.length } }];

const data = $input.first().json;
const deepCandidates = Array.isArray(data.deepCandidates) ? data.deepCandidates : [];
return deepCandidates.map((deepCandidate, index) => ({
  json: {
    analysisId: data.analysisId,
    projectName: data.projectName,
    dependencyStats: data.dependencyStats,
    allCandidates: data.allCandidates,
    deepCandidate,
    candidatePosition: index + 1,
    totalDeepCandidates: deepCandidates.length,
    skipResearch: false
  }
}));

const base = $('Tier packages').first().json;
const deepBriefs = $input.all().map((item) => item.json?.packageBrief).filter(Boolean);
const shallowCandidates = Array.isArray(base.shallowCandidates) ? base.shallowCandidates : [];
const formatDate = (value) => {
  if (!value) return null;
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed.toISOString().slice(0, 10);
};
const getResolution = (candidate) => candidate?.resolution ?? {};
const getComparisonStatus = (candidate) => getResolution(candidate).comparisonStatus ?? 'unresolved';
const getDeclaredSpec = (candidate) => getResolution(candidate).declaredSpec ?? candidate.currentVersion;
const getWantedVersion = (candidate) => getResolution(candidate).wantedVersion ?? candidate.currentVersion;
const getLatestVersion = (candidate) => getResolution(candidate).latestVersion ?? candidate.latestVersion;
const getDisplayStatus = (candidate) => {
  const comparisonStatus = getComparisonStatus(candidate);
  if (comparisonStatus === 'up_to_date') {
    return getDeclaredSpec(candidate) !== getWantedVersion(candidate)
      ? 'covered_by_range'
      : 'up_to_date';
  }
  if (comparisonStatus === 'outdated') {
    return 'outdated';
  }
  return 'manual_review';
};
const summarize = (candidate) => {
  const publishedAt = formatDate(candidate.publishedAt);
  const resolution = getResolution(candidate);
  const declaredSpec = getDeclaredSpec(candidate);
  const wantedVersion = getWantedVersion(candidate);
  const latestVersion = getLatestVersion(candidate);
  const displayStatus = getDisplayStatus(candidate);
  const tone = displayStatus === 'manual_review'
    ? `Spec ${declaredSpec} requiere revisión manual (${resolution.specKind ?? 'unknown'}); no se asume un upgrade automático fiable.`
    : candidate.deprecated
      ? `La resolución apunta a un estado deprecated (${resolution.deprecationStatus ?? 'wanted_deprecated'}) y conviene planificar salida o reemplazo.`
      : displayStatus === 'covered_by_range'
        ? `El spec ya cubre la latest del registry y no requiere cambio en package.json.`
        : displayStatus === 'up_to_date'
          ? `El paquete ya está alineado con la latest del registry y no requiere cambio en package.json.`
          : candidate.diffType === 'major'
            ? 'Evidencia parcial basada en semver y metadata; trata el cambio como potencialmente breaking hasta revisar fuentes oficiales.'
            : candidate.diffType === 'minor'
              ? 'Evidencia parcial basada en metadata; upgrade incremental con riesgo acotado si la cobertura actual es razonable.'
              : 'Evidencia parcial basada en metadata; patch orientado a fixes y estabilidad.';
  return `Spec ${declaredSpec}. Wanted ${wantedVersion}; latest ${latestVersion}. ${tone}${publishedAt ? ` Latest published ${publishedAt}.` : ''}`;
};
const buildSources = (candidate) => {
  const npmPackageName = getResolution(candidate).registryPackageName ?? candidate.name;
  const sources = [{ packageName: candidate.name, label: 'npm', url: `https://www.npmjs.com/package/${npmPackageName}` }];
  if (candidate.repositoryUrl) sources.push({ packageName: candidate.name, label: 'repository', url: candidate.repositoryUrl });
  return sources;
};
const shallowBriefs = shallowCandidates.map((candidate) => {
  const displayStatus = getDisplayStatus(candidate);
  const comparisonStatus = getComparisonStatus(candidate);
  return {
    name: candidate.name,
    summary: summarize(candidate),
    breakingChanges: [],
    testFocus: candidate.deprecated
      ? ['Validar rutas donde aun dependa el paquete deprecated', 'Buscar reemplazo funcional antes del siguiente release']
      : displayStatus === 'manual_review'
        ? ['Verificar manualmente el spec y su canal antes de cambiar el comportamiento actual', 'Confirmar compatibilidad técnica con build, imports y runtime']
        : comparisonStatus === 'outdated'
          ? ['Smoke test del flujo principal afectado', 'Validar build, imports y arranque del proyecto']
          : ['No requiere cambio inmediato en package.json', 'Volver a revisar solo si cambia el spec declarado o aparece nueva evidencia'],
    riskLevel: candidate.deprecated || candidate.diffType === 'major' || displayStatus === 'manual_review'
      ? 'high'
      : candidate.diffType === 'minor'
        ? 'medium'
        : 'low',
    confidence: displayStatus === 'manual_review' ? 'low' : 'medium',
    evidenceStatus: 'partial',
    recommendedActions: candidate.deprecated
      ? ['Congelar nuevas integraciones sobre este paquete', 'Priorizar sustitucion o remocion gradual']
      : displayStatus === 'manual_review'
        ? ['Tratar este paquete como manual review/custom spec antes de proponer upgrades', 'Revisar wanted/latest y confirmar si corresponde mantener el comportamiento actual']
        : comparisonStatus === 'outdated'
          ? ['Aplicar upgrade en una rama corta', 'Confirmar que no cambie el build ni el runtime']
          : ['No abrir un ticket de upgrade solo por este paquete', 'Reevaluarlo si cambia el spec declarado o la latest del registry'],
    sources: buildSources(candidate)
  };
});
const allCandidates = Array.isArray(base.allCandidates) ? base.allCandidates : [];
const briefMap = new Map();
for (const brief of shallowBriefs) briefMap.set(brief.name, brief);
for (const brief of deepBriefs) briefMap.set(brief.name, brief);
const packageBriefs = allCandidates.map((candidate) => briefMap.get(candidate.name)).filter(Boolean);
const sources = [];
const seen = new Set();
for (const brief of packageBriefs) {
  for (const source of brief.sources ?? []) {
    const key = `${source.packageName}|${source.label}|${source.url}`;
    if (!seen.has(key)) {
      seen.add(key);
      sources.push(source);
    }
  }
}
const evidenceCoverage = { verified: 0, partial: 0, none: 0 };
for (const brief of packageBriefs) {
  const key = ['verified', 'partial', 'none'].includes(brief.evidenceStatus) ? brief.evidenceStatus : 'none';
  evidenceCoverage[key] += 1;
}
const verifiedPackages = packageBriefs.filter((brief) => brief.evidenceStatus === 'verified').map((brief) => brief.name);
const partialPackages = packageBriefs.filter((brief) => brief.evidenceStatus === 'partial').map((brief) => brief.name);
const nonePackages = packageBriefs.filter((brief) => brief.evidenceStatus === 'none').map((brief) => brief.name);
const actionablePackages = allCandidates
  .filter((candidate) => getComparisonStatus(candidate) === 'outdated' || candidate.deprecated)
  .map((candidate) => candidate.name);
const coveredByRangePackages = allCandidates
  .filter((candidate) => getDisplayStatus(candidate) === 'covered_by_range')
  .map((candidate) => candidate.name);
const alignedPackages = allCandidates
  .filter((candidate) => getDisplayStatus(candidate) === 'up_to_date')
  .map((candidate) => candidate.name);
const manualReviewPackages = allCandidates
  .filter((candidate) => getDisplayStatus(candidate) === 'manual_review')
  .map((candidate) => candidate.name);
return [{ json: { analysisId: base.analysisId, projectName: base.projectName, dependencyStats: base.dependencyStats, allCandidates, quickWins: base.quickWins ?? [], highRisk: base.highRisk ?? [], packageBriefs, sources, evidenceCoverage, verifiedPackages, partialPackages, nonePackages, actionablePackages, coveredByRangePackages, alignedPackages, manualReviewPackages } }];

const raw = $input.first().json;
const parsed = raw.output ?? raw.response ?? raw;

const base = $('Merge package briefs').first().json;
const coverage = base.evidenceCoverage ?? { verified: 0, partial: 0, none: 0 };

const fallbackPlan = [
  {
    wave: 1,
    title: 'Fase 1 - Quick wins controlados',
    rationale: 'Aplicar upgrades con menor riesgo y evidencia suficiente para mover rapido sin romper la base del proyecto.',
    packages: (base.quickWins ?? []).map((pkg) => pkg.name).filter(Boolean)
  },
  {
    wave: 2,
    title: 'Fase 2 - Riesgo alto y deprecated',
    rationale: 'Resolver majors, paquetes deprecated y cambios con mayor necesidad de validacion antes de mergear.',
    packages: (base.highRisk ?? []).map((pkg) => pkg.name).filter(Boolean)
  }
];

const fallbackSummary = `Se completo la investigacion por paquete para ${base.projectName}. Cobertura actual: ${coverage.verified} paquetes con evidencia verified, ${coverage.partial} con evidencia partial y ${coverage.none} sin evidencia suficiente. Si la sintesis automatica no puede verificarse, usa los packageBriefs como fuente principal para decidir el plan de upgrade.`;

const fallbackSlackDigest = `Investigacion completada para ${base.projectName}: ${coverage.verified} verified, ${coverage.partial} partial, ${coverage.none} none. Prioriza high risk y deprecated antes de mergear.`;

const resolved =
  parsed && typeof parsed === 'object' && !Array.isArray(parsed)
    ? parsed
    : {
        analysisId: base.analysisId,
        status: 'completed',
        executiveSummaryMd: fallbackSummary,
        upgradePlan: fallbackPlan,
        slackDigestMd: fallbackSlackDigest,
        sources: base.sources ?? []
      };

const allowedSources = new Map();
for (const source of base.sources ?? []) {
  const packageName = String(source?.packageName ?? '');
  const label = String(source?.label ?? '');
  const url = String(source?.url ?? '');
  if (!packageName || !label || !url) continue;
  if (!allowedSources.has(url)) {
    allowedSources.set(url, { packageName, label, url });
  }
}

const dedupedSources = [];
const seen = new Set();

for (const source of [...(resolved.sources ?? []), ...(base.sources ?? [])]) {
  const url = String(source?.url ?? '');
  const canonical = allowedSources.get(url);
  if (!canonical) continue;

  const key = `${canonical.packageName}|${canonical.label}|${canonical.url}`;
  if (seen.has(key)) continue;

  seen.add(key);
  dedupedSources.push(canonical);
}

return [
  {
    json: {
      analysisId: resolved.analysisId || base.analysisId,
      status: 'completed',
      executiveSummaryMd: resolved.executiveSummaryMd ?? fallbackSummary,
      upgradePlan: Array.isArray(resolved.upgradePlan) ? resolved.upgradePlan : fallbackPlan,
      packageBriefs: base.packageBriefs ?? [],
      slackDigestMd: resolved.slackDigestMd ?? fallbackSlackDigest,
      sources: dedupedSources
    }
  }
];

const source = $input.first().json;
const fallback = $('Validate input').first().json;
const base = $('Merge package briefs').first()?.json ?? null;

const message =
  source.error?.message ??
  source.message ??
  source.statusMessage ??
  'No se pudo generar el brief final en n8n. Revisa Groq o el parser y vuelve a intentar.';

if (base?.packageBriefs?.length) {
  const coverage = base.evidenceCoverage ?? { verified: 0, partial: 0, none: 0 };

  return [
    {
      json: {
        analysisId: base.analysisId ?? fallback.analysisId,
        status: 'completed',
        executiveSummaryMd: `Se completo la investigacion por paquete, pero fallo la sintesis ejecutiva automatizada. ${message}`,
        upgradePlan: [
          {
            wave: 1,
            title: 'Fase 1 - Quick wins controlados',
            rationale: 'Mover quick wins con validacion basica mientras se revisan cambios sensibles.',
            packages: (base.quickWins ?? []).map((pkg) => pkg.name).filter(Boolean)
          },
          {
            wave: 2,
            title: 'Fase 2 - Riesgo alto y deprecated',
            rationale: 'Resolver majors, deprecated y paquetes con evidencia que requiere revision adicional.',
            packages: (base.highRisk ?? []).map((pkg) => pkg.name).filter(Boolean)
          }
        ],
        packageBriefs: base.packageBriefs,
        slackDigestMd: `Sintesis ejecutiva degradada: ${coverage.verified} verified, ${coverage.partial} partial, ${coverage.none} none. Usa packageBriefs y fuentes antes de mergear.`,
        sources: base.sources ?? []
      }
    }
  ];
}

return [
  {
    json: {
      analysisId: fallback.analysisId,
      status: 'failed',
      executiveSummaryMd: message,
      upgradePlan: [],
      packageBriefs: [],
      sources: []
    }
  }
];
